// Integration test: actually execute the bash script generated by
// buildSwapAndRelaunchScript against a synthetic .app and parent process.
// Verifies the swap, the cleanup, and the relaunch invocation work end-to-end.

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import fs from 'node:fs';
import path from 'node:path';
import os from 'node:os';
import { spawn, spawnSync } from 'node:child_process';
import { buildSwapAndRelaunchScript } from '../../electron/updater-install-helpers.cjs';

const RUN_TIMEOUT_MS = 15000;

function makeFakeBundle(dir, marker) {
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, 'MARKER.txt'), marker);
}

function runScriptToCompletion(script, parentPid) {
  return new Promise((resolve, reject) => {
    const child = spawn('/bin/bash', ['-c', script], { stdio: 'pipe' });
    let stderr = '';
    child.stderr.on('data', (c) => { stderr += c.toString(); });
    child.stdout.on('data', () => {});
    const timer = setTimeout(() => {
      child.kill('SIGKILL');
      reject(new Error('Script did not finish in ' + RUN_TIMEOUT_MS + 'ms (stderr=' + stderr + ')'));
    }, RUN_TIMEOUT_MS);
    child.on('exit', (code) => {
      clearTimeout(timer);
      resolve({ code, stderr });
    });
    child.on('error', (err) => {
      clearTimeout(timer);
      reject(err);
    });
  });
}

// Spawns a short-lived sleep process whose PID we hand to the installer
// script as `parentPid`. After we kill it, the script proceeds.
function spawnSleeper() {
  const sleeper = spawn('/bin/sleep', ['60'], { stdio: 'ignore', detached: false });
  return sleeper;
}

describe('swap-and-relaunch script (integration)', () => {
  let tmpDir;
  let stagedPath;
  let targetParent;
  let targetPath;
  let openMarkerFile;
  let logPath;

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'swap-script-'));
    stagedPath = path.join(tmpDir, 'staged', 'Redstring.app');
    targetParent = path.join(tmpDir, 'apps');
    targetPath = path.join(targetParent, 'Redstring.app');
    openMarkerFile = path.join(tmpDir, 'opened.txt');
    logPath = path.join(tmpDir, 'installer.log');
    fs.mkdirSync(targetParent, { recursive: true });
  });

  afterEach(() => {
    try { fs.rmSync(tmpDir, { recursive: true, force: true }); } catch { /* ignore */ }
  });

  it('swaps the staged bundle into the target location', async () => {
    makeFakeBundle(stagedPath, 'NEW_BUNDLE');
    makeFakeBundle(targetPath, 'OLD_BUNDLE');

    const sleeper = spawnSleeper();
    const script = buildSwapAndRelaunchScript({
      stagedBundlePath: stagedPath,
      targetBundlePath: targetPath,
      parentPid: sleeper.pid,
      logPath,
      openCommand: `/bin/sh -c 'printf %s "OPENED:$1" > ${openMarkerFile}' --`,
      maxWaitSeconds: 8
    });

    // Kill the fake parent so the wait loop in the script exits.
    setTimeout(() => sleeper.kill('SIGTERM'), 300);

    const { code, stderr } = await runScriptToCompletion(script, sleeper.pid);
    expect(code, 'script stderr=' + stderr).toBe(0);

    expect(fs.existsSync(targetPath)).toBe(true);
    expect(fs.readFileSync(path.join(targetPath, 'MARKER.txt'), 'utf-8')).toBe('NEW_BUNDLE');
    expect(fs.existsSync(stagedPath)).toBe(false);

    // No leftover ".Redstring.app.old.*" trash next to the target.
    const siblings = fs.readdirSync(targetParent);
    const leftovers = siblings.filter((n) => n.startsWith('.Redstring.app.old.'));
    expect(leftovers, 'unexpected leftover ' + leftovers.join(',')).toEqual([]);

    expect(fs.existsSync(openMarkerFile)).toBe(true);
    expect(fs.readFileSync(openMarkerFile, 'utf-8')).toBe('OPENED:' + targetPath);
  });

  it('aborts cleanly when the staged bundle is missing', async () => {
    // Don't create stagedPath
    makeFakeBundle(targetPath, 'OLD_BUNDLE');

    const sleeper = spawnSleeper();
    const script = buildSwapAndRelaunchScript({
      stagedBundlePath: stagedPath,
      targetBundlePath: targetPath,
      parentPid: sleeper.pid,
      logPath,
      openCommand: `/bin/sh -c 'echo SHOULD_NOT_OPEN > ${openMarkerFile}' --`,
      maxWaitSeconds: 8
    });

    setTimeout(() => sleeper.kill('SIGTERM'), 300);
    const { code } = await runScriptToCompletion(script, sleeper.pid);

    expect(code).not.toBe(0);
    expect(fs.existsSync(targetPath)).toBe(true);
    expect(fs.readFileSync(path.join(targetPath, 'MARKER.txt'), 'utf-8')).toBe('OLD_BUNDLE');
    expect(fs.existsSync(openMarkerFile)).toBe(false);

    const log = fs.readFileSync(logPath, 'utf-8');
    expect(log).toMatch(/staged bundle missing/);
  });

  it('aborts if the parent process never exits within maxWaitSeconds', async () => {
    makeFakeBundle(stagedPath, 'NEW_BUNDLE');
    makeFakeBundle(targetPath, 'OLD_BUNDLE');

    const sleeper = spawnSleeper();
    try {
      const script = buildSwapAndRelaunchScript({
        stagedBundlePath: stagedPath,
        targetBundlePath: targetPath,
        parentPid: sleeper.pid,
        logPath,
        openCommand: `/bin/sh -c 'echo SHOULD_NOT_OPEN > ${openMarkerFile}' --`,
        maxWaitSeconds: 2
      });

      const { code } = await runScriptToCompletion(script, sleeper.pid);
      expect(code).not.toBe(0);

      expect(fs.readFileSync(path.join(targetPath, 'MARKER.txt'), 'utf-8')).toBe('OLD_BUNDLE');
      expect(fs.existsSync(stagedPath)).toBe(true);
      expect(fs.existsSync(openMarkerFile)).toBe(false);
    } finally {
      sleeper.kill('SIGKILL');
    }
  });

  it('handles a missing target gracefully (first install)', async () => {
    makeFakeBundle(stagedPath, 'NEW_BUNDLE');
    // No existing target

    const sleeper = spawnSleeper();
    const script = buildSwapAndRelaunchScript({
      stagedBundlePath: stagedPath,
      targetBundlePath: targetPath,
      parentPid: sleeper.pid,
      logPath,
      openCommand: `/bin/sh -c 'printf OPENED > ${openMarkerFile}' --`,
      maxWaitSeconds: 8
    });

    setTimeout(() => sleeper.kill('SIGTERM'), 300);
    const { code, stderr } = await runScriptToCompletion(script, sleeper.pid);
    expect(code, 'stderr=' + stderr).toBe(0);

    expect(fs.existsSync(targetPath)).toBe(true);
    expect(fs.readFileSync(path.join(targetPath, 'MARKER.txt'), 'utf-8')).toBe('NEW_BUNDLE');
    expect(fs.existsSync(openMarkerFile)).toBe(true);
  });
});
